const input = $json || {};
const marketingChannelId = 'C0AVCULL4A0';
const marianaMention = '<@U0AV78P1486>';

function extractSlackText(payload) {
  const raw = typeof payload.text === 'string' ? payload.text : '';
  if (raw.trim()) {
    return raw.replace(/<@[A-Z0-9]+>/g, '').replace(/\s+/g, ' ').trim();
  }

  const parts = [];
  for (const block of payload.blocks || []) {
    for (const element of block.elements || []) {
      for (const item of element.elements || []) {
        if (item.type === 'text' && item.text) {
          parts.push(item.text);
        }
      }
    }
  }

  return parts.join(' ').replace(/\s+/g, ' ').trim();
}

const isSlackEvent = Boolean(input.channel || input.user || input.text || input.blocks);
const ts = input.ts || input.event_ts || $now.toISO();
const threadTs = isSlackEvent ? (input.thread_ts || ts) : '';
const message = isSlackEvent
  ? extractSlackText(input)
  : [
      'MODO CRON: revise autonomamente a fila de leads em Novo Lead do funil de aquisição.',
      'Analise histórico, mensagens, sinais de fit, desqualificação e contexto de agenda.',
      'Mova para Qualificação quando houver oportunidade real.',
      'Mova para Nutrição quando houver fit, mas ainda depender de follow-up ou maturação.',
      'Mova para Descartado quando não houver fit, houver desalinhamento definitivo ou postura desrespeitosa.',
      'Quando fizer sentido, recomende um follow-up claro para a Mariana.',
      'Se nenhuma mudança relevante for feita nesta execução, não envie mensagem no Slack.'
    ].join(' ');

return [{
  json: {
    message,
    raw_text: isSlackEvent ? (input.text || '') : message,
    channel: isSlackEvent ? input.channel : marketingChannelId,
    ts,
    thread_ts: threadTs,
    user: isSlackEvent ? input.user : 'schedule_trigger',
    type: isSlackEvent ? input.type : 'schedule',
    is_thread: isSlackEvent ? !!input.thread_ts : false,
    conversation_key: isSlackEvent
      ? `${input.channel || 'unknown'}:${threadTs || ts || input.user || 'unknown'}`
      : 'cron:lucas-andrade-qualification',
    source: isSlackEvent ? 'slack_internal_novian' : 'scheduled_novo_lead_review',
    execution_mode: isSlackEvent ? 'slack' : 'cron',
    marketing_channel_id: marketingChannelId,
    mariana_mention: marianaMention,
    mariana_fallback_mention: '@Mariana Silva',
    qualified_stage: 'Qualificação',
    nurture_stage: 'Nutrição',
    discarded_stage: 'Descartado'
  }
}];

const original = $('Normalize Execution Context').first().json;
const people = $items('Buscar leads Novo Lead').map((item) => item.json);
const properties = $items('Buscar imóveis ativos').map((item) => item.json);

function compact(value) {
  if (Array.isArray(value)) {
    return value
      .map((item) => compact(item))
      .filter((item) => item !== null && item !== undefined && item !== '' && !(Array.isArray(item) && item.length === 0));
  }

  if (value && typeof value === 'object') {
    const result = {};
    for (const [key, item] of Object.entries(value)) {
      if (item === null || item === undefined || item === '') continue;
      const normalized = compact(item);
      if (normalized === null || normalized === undefined || normalized === '') continue;
      if (Array.isArray(normalized) && normalized.length === 0) continue;
      if (normalized && typeof normalized === 'object' && !Array.isArray(normalized) && Object.keys(normalized).length === 0) continue;
      result[key] = normalized;
    }
    return result;
  }

  return value;
}

function summarizeCounts(items, key) {
  const counts = new Map();
  for (const item of items) {
    const value = String(item?.[key] || 'sem_' + key).trim() || 'sem_' + key;
    counts.set(value, (counts.get(value) || 0) + 1);
  }

  return Array.from(counts.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 6)
    .map(([label, count]) => `${label}: ${count}`)
    .join(' | ') || 'Sem dados suficientes';
}

const simplifiedPeople = people.map((person) => compact(person));
const simplifiedProperties = properties.map((property) => compact(property));

return [{
  json: {
    ...original,
    people_count: simplifiedPeople.length,
    properties_count: simplifiedProperties.length,
    people_status_summary: summarizeCounts(simplifiedPeople, 'crm_status'),
    people_intent_summary: summarizeCounts(simplifiedPeople, 'intent'),
    people_context: simplifiedPeople.length
      ? JSON.stringify(simplifiedPeople, null, 2)
      : 'Nenhum lead em Novo Lead encontrado no snapshot atual da tabela people.',
    properties_context: simplifiedProperties.length
      ? JSON.stringify(simplifiedProperties, null, 2)
      : 'Nenhum imóvel ativo encontrado no snapshot atual da tabela properties.'
  }
}];

